const base64Data = $input.item.json.input;
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(base64Data, 'base64'),
  $input.item.json.filename || 'report.pdf',
  'application/pdf'
);

return [{
  json: {
    sessionId: $input.item.json.sessionId,
    filename: $input.item.json.filename
  },
  binary: {
    data: binaryData
  }
}];
